import React, { useCallback } from 'react';

interface DatePickerProps {
  name: string;
  label: string;
  value: string;
  onChange: (value: string) => void;
  error?: string;
  required?: boolean;
  minDate?: string;
  maxDate?: string;
}

function validateDate(value: string, minDate?: string, maxDate?: string): string | undefined {
  if (!value) return undefined;
  if (minDate && value < minDate) {
    return `Date must be on or after ${minDate}`;
  }
  if (maxDate && value > maxDate) {
    return `Date must be on or before ${maxDate}`;
  }
  return undefined;
}

export const DatePicker: React.FC<DatePickerProps> = ({
  name, label, value, onChange, error, required, minDate, maxDate
}) => {
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      onChange(e.target.value);
    },
    [onChange]
  );

  const validationError = error || validateDate(value, minDate, maxDate);

  return (
    <div className="form-field">
      <label htmlFor={name}>{label}{required && ' *'}</label>
      <input
        id={name}
        type="date"
        value={value}
        onChange={handleChange}
        min={minDate}
        max={maxDate}
        className={validationError ? 'input-error' : ''}
      />
      {validationError && <span className="error-msg">{validationError}</span>}
    </div>
  );
};

